// --- 3D CARD COMPONENT ---
function TeamCard3D({ member, position }: { member: any; position: [number, number, number] }) {
  const mesh = useRef<THREE.Group>(null!)
  const [hovered, setHovered] = useState(false)

  useFrame((state) => {
    if (mesh.current) {
      const x = (state.mouse.x * Math.PI) / 10
      const y = (state.mouse.y * Math.PI) / 10
      mesh.current.rotation.x = THREE.MathUtils.lerp(mesh.current.rotation.x, hovered ? -y : 0, 0.1)
      mesh.current.rotation.y = THREE.MathUtils.lerp(mesh.current.rotation.y, hovered ? x : 0, 0.1)
      const targetScale = hovered ? 1.05 : 1
      mesh.current.scale.setScalar(THREE.MathUtils.lerp(mesh.current.scale.x, targetScale, 0.1))
    }
  })

  return (
    <group position={position} ref={mesh}>
      <Float speed={1.5} rotationIntensity={0.1} floatIntensity={0.4}>
        <mesh onPointerOver={() => setHovered(true)} onPointerOut={() => setHovered(false)}>
          <planeGeometry args={[3.2, 4.2]} />
          <Suspense fallback={<meshStandardMaterial color="#1e293b" />}>
            <Image url={member.image} transparent />
          </Suspense>
        </mesh>

        <mesh position={[0, 0, -0.05]}>
          <planeGeometry args={[3.3, 4.3]} />
          <MeshDistortMaterial 
            color={hovered ? "#6366f1" : "#0f172a"} 
            speed={3} 
            distort={0.2} 
            radius={1} 
          />
        </mesh>

        <Text
          position={[0, -2.6, 0.1]}
          fontSize={0.22}
          color="white"
          anchorX="center"
          maxWidth={3}
        >
          {`${member.name}\n${member.role}`}
        </Text>
      </Float>
    </group>
  )
}

